$hosts = @('8.8.8.8', '1.1.1.1', 'google.com', 'dc01.empresa.local')
foreach ($h in $hosts) {
  $r = Test-Connection $h -Count 2 -Quiet
  Write-Host "$h : $(if ($r) {'✅ OK'} else {'❌ FAIL'})"
}

$host = '192.168.1.1'
$puertos = @(80, 443, 445, 3389, 22)
foreach ($p in $puertos) {
  $r = Test-NetConnection $host -Port $p -WarningAction SilentlyContinue
  Write-Host "Puerto $p : $(if ($r.TcpTestSucceeded) {'✅ ABIERTO'} else {'❌ CERRADO'})"
}

Connect-MsolService
$user = 'usuario@empresa.com'
$u = Get-MsolUser -UserPrincipalName $user
$mfaState = $u.StrongAuthenticationRequirements
if ($mfaState) {
  Write-Host "✅ MFA habilitado: $($mfaState.State)"
} else {
  Write-Host '⚠️ MFA no configurado'
}

Get-CimInstance Win32_PhysicalMemory | Select-Object Manufacturer, Capacity, Speed, MemoryType | ForEach-Object {
  [PSCustomObject]@{
    Fabricante = $_.Manufacturer
    CapacidadGB = [math]::Round($_.Capacity/1GB, 2)
    VelocidadMHz = $_.Speed
  }
} | Format-Table -AutoSize

Get-PhysicalDisk | Select-Object FriendlyName, MediaType, Size, HealthStatus, OperationalStatus | ForEach-Object {
  [PSCustomObject]@{
    Disco = $_.FriendlyName
    Tipo = $_.MediaType
    TamañoGB = [math]::Round($_.Size/1GB, 1)
    Salud = $_.HealthStatus
  }
} | Format-Table -AutoSize

$proceso = 'chrome'
$umbralCPU = 50
$intervalo = 5  # segundos

Write-Host "Monitoreando $proceso (umbral CPU: $umbralCPU%)..."
while ($true) {
  $proc = Get-Process $proceso -ErrorAction SilentlyContinue
  if ($proc) {
    $cpu = [math]::Round(($proc | Measure-Object CPU -Sum).Sum, 2)
    if ($cpu -gt $umbralCPU) {
      Write-Host "⚠️ ALERTA: $proceso usa $cpu% CPU" -ForegroundColor Red
    } else {
      Write-Host "$(Get-Date -Format 'HH:mm:ss') | $proceso CPU: $cpu%"
    }
  } else {
    Write-Host "❌ Proceso $proceso no encontrado"
  }
  Start-Sleep $intervalo
}
